import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import {headerStrings, MyTable, headerActions, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, InfoText } from '../../../includes';
import { Button } from '@material-ui/core';
import { colors } from '../../../../utils';
import { staffStrings } from '../config';
import { staffActions } from '../actions';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
        marginTop : 20
    },
    newBtn : {
        backgroundColor : colors.secondary
    }
})
class _OtherStaff extends Component {
    constructor(props) {
        super(props);
        headerActions({
            [headerStrings.headerTitle] : "Staff (Others)",
            [headerStrings.backButtonAction] : null
        })(props.dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Staff", path : routeNamesSchool.adminStaff},
        ])(props.dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [{
                value : "New Staff", className : props.classes.newBtn, 
                onClick : ()=>props.history.push(routeNamesSchool.newOtherStaff)
            }]
        })(props.dispatch);
        staffActions.getStaff.others()(props.dispatch);
    }
    componentDidMount(){
       
    }
    newStaffButton = () => <Button style={{backgroundColor : colors.secondary}}>New Staff</Button>;
    header = ["", "Last Name", "First Name", "Address", "Email", "Phone"];
    dataMap = ["action", "lastName", "firstName", "address", "email", "phone"]
    render() {
        const {classes, [staffStrings.staffListOthers] : adminStaff = []} = this.props;
        return (
            <div className={classes.root}>
                <InfoText>Click on the table row (staff) to select</InfoText>
                <MyTable
                    header={this.header}
                    dataMap={this.dataMap}
                    data={adminStaff}/>
            </div>
        );
    }
}


_OtherStaff.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({staffReducer}) => ({
    [staffStrings.staffListOthers] : staffReducer[staffStrings.staffListOthers]
})


export const OtherStaff = connect(mapStateToProps)(withStyles(style)(_OtherStaff));
export {OtherStaff as default};